if (name === 'onSend' || name === 'preSerialization' || name === 'onError' || name === 'preParsing') {
  if (fn.constructor.name === 'AsyncFunction' && fn.length === 4) {
    throw new errorCodes.FST_ERR_HOOK_INVALID_ASYNC_HANDLER()
  }
} else if (name === 'onReady' || name === 'onListen') {
  if (fn.constructor.name === 'AsyncFunction' && fn.length !== 0) {
    throw new errorCodes.FST_ERR_HOOK_INVALID_ASYNC_HANDLER()
  }
} else if (name === 'onRequestAbort') {
  if (fn.constructor.name === 'AsyncFunction' && fn.length !== 1) {
    throw new errorCodes.FST_ERR_HOOK_INVALID_ASYNC_HANDLER()
  }
} else {
  if (fn.constructor.name === 'AsyncFunction' && fn.length === 3) {
    throw new errorCodes.FST_ERR_HOOK_INVALID_ASYNC_HANDLER()
  }
}

return function onAsyncConstraintError (err) {
  if (err) {
    if (options.frameworkErrors) {
      const id = getGenReqId(routeEventContext.server, req)
      const childLogger = createChildLogger(routeEventContext, options.logger, req, id)

      const request = new Request(id, null, req, null, childLogger, routeEventContext)
      const reply = new Reply(res, request, childLogger)

      const resolvedDisableRequestLogging = typeof disableRequestLogging === 'function' ? disableRequestLogging(req) : disableRequestLogging
      if (resolvedDisableRequestLogging === false) {
        childLogger.info({ req: request }, 'incoming request')
      }

      return options.frameworkErrors(new FST_ERR_ASYNC_CONSTRAINT(), request, reply)
    }
    const body = '{"error":"Internal Server Error","message":"Unexpected error from async constraint","statusCode":500}'
    res.writeHead(500, {
      'Content-Type': 'application/json',
      'Content-Length': body.length
    })
    res.end(body)
  }
}

try {
  const serializerFn = getSchemaSerializer(reply[kRouteContext], statusCode, reply[kReplyHeaders]['content-type'])
  if (serializerFn === false) {
    payload = serializeError({
      error: statusCodes[statusCode + ''],
      code: error.code,
      message: error.message,
      statusCode
    })
  } else {
    payload = serializerFn(Object.create(error, {
      error: { value: statusCodes[statusCode + ''] },
      message: { value: error.message },
      statusCode: { value: statusCode }
    }))
  }
} catch (err) {
  if (!reply.log[kDisableRequestLogging]) {
    // error is always FST_ERR_SCH_SERIALIZATION_BUILD because this is called from route/compileSchemasForSerialization
    reply.log.error({ err, statusCode: res.statusCode }, 'The serializer for the given status code failed')
  }
  reply.code(500)
  payload = serializeError(new FST_ERR_FAILED_ERROR_SERIALIZATION(err.message, error.message))
}

if (payload != null && typeof payload === 'object' && toString.call(payload) === '[object Response]') {
  // https://developer.mozilla.org/en-US/docs/Web/API/Response/status
  if (typeof payload.status === 'number') {
    reply.code(payload.status)
  }

  // https://developer.mozilla.org/en-US/docs/Web/API/Response/headers
  if (typeof payload.headers === 'object' && typeof payload.headers.forEach === 'function') {
    for (const [headerName, headerValue] of payload.headers) {
      reply.header(headerName, headerValue)
    }
  }

  // https://developer.mozilla.org/en-US/docs/Web/API/Response/body
  if (payload.body !== null) {
    if (payload.bodyUsed) {
      throw new FST_ERR_REP_RESPONSE_BODY_CONSUMED()
    }
  }
  // Keep going, body is either null or ReadableStream
  payload = payload.body
}

for (const trailerName of trailerHeaders) {
  if (typeof reply[kReplyTrailers][trailerName] !== 'function') continue
  skipped = false
  handled--

  let cbAlreadyCalled = false
  function cb (err, value) {
    if (cbAlreadyCalled) return
    cbAlreadyCalled = true
    handled++

    // we can safely ignore error for trailer
    // since it does affect the client
    // we log in here only for debug usage
    if (err) reply.log.debug(err)
    else trailers[trailerName] = value

    // we push the check to the end of event
    // loop, so the registration continue to
    // process.
    process.nextTick(send)
  }

  const result = reply[kReplyTrailers][trailerName](reply, payload, cb)
  if (typeof result === 'object' && typeof result.then === 'function') {
    result.then((v) => cb(null, v), cb)
  }
}

const onResFinished = err => {
  reply[kReplyEndTime] = now()
  reply.raw.removeListener('finish', onResFinished)
  reply.raw.removeListener('error', onResFinished)

  const ctx = reply[kRouteContext]

  // Clean up handler timeout / signal resources
  if (reply.request[kRequestSignal]) {
    clearTimeout(reply.request[kTimeoutTimer])
    reply.request[kTimeoutTimer] = null
    if (reply.request[kOnAbort]) {
      reply.request.raw.removeListener('close', reply.request[kOnAbort])
      reply.request[kOnAbort] = null
    }
  }

  if (ctx && ctx.onResponse !== null) {
    onResponseHookRunner(
      ctx.onResponse,
      reply.request,
      reply,
      onResponseCallback
    )
  } else {
    onResponseCallback(err, reply.request, reply)
  }
}

if (path === '/' && prefix.length > 0 && opts.method !== 'HEAD') {
  switch (opts.prefixTrailingSlash) {
    case 'slash':
      addNewRoute.call(this, { path, isFastify })
      break
    case 'no-slash':
      addNewRoute.call(this, { path: '', isFastify })
      break
    case 'both':
    default:
      addNewRoute.call(this, { path: '', isFastify })
      // If ignoreTrailingSlash is set to true we need to add only the '' route to prevent adding an incomplete one.
      if (ignoreTrailingSlash !== true && (ignoreDuplicateSlashes !== true || !prefix.endsWith('/'))) {
        addNewRoute.call(this, { path, prefixing: true, isFastify })
      }
  }
} else if (path[0] === '/' && prefix.endsWith('/')) {
  // Ensure that '/prefix/' + '/route' gets registered as '/prefix/route'
  addNewRoute.call(this, { path: path.slice(1), isFastify })
} else {
  addNewRoute.call(this, { path, isFastify })
}

http2Server.on('session', function (session) {
  session.once('connect', function () {
    http2Server[kHttp2ServerSessions].add(session)
  })

  session.once('close', function () {
    http2Server[kHttp2ServerSessions].delete(session)
  })

  session.once('frameError', function (type, code, streamId) {
    if (streamId === 0) {
      // The stream ID is 0, which means that the error is related to the session itself.
      // If the event is not associated with a stream, the Http2Session will be shut down immediately
      http2Server[kHttp2ServerSessions].delete(session)
    }
  })

  session.once('goaway', function () {
    // The Http2Session instance will be shut down automatically when the 'goaway' event is emitted.
    http2Server[kHttp2ServerSessions].delete(session)
  })
})

if (headers && (isCustom || Object.getPrototypeOf(headers) !== Object.prototype)) {
  // do not mess with schema when custom validator applied, e.g. Joi, Typebox
  context[headersSchema] = compile({ schema: headers, method, url, httpPart: 'headers' })
} else if (headers) {
  // The header keys are case insensitive
  //  https://datatracker.ietf.org/doc/html/rfc2616#section-4.2
  const headersSchemaLowerCase = {}
  Object.keys(headers).forEach(k => { headersSchemaLowerCase[k] = headers[k] })
  if (headersSchemaLowerCase.required instanceof Array) {
    headersSchemaLowerCase.required = headersSchemaLowerCase.required.map(h => h.toLowerCase())
  }
  if (headers.properties) {
    headersSchemaLowerCase.properties = {}
    Object.keys(headers.properties).forEach(k => {
      headersSchemaLowerCase.properties[k.toLowerCase()] = headers.properties[k]
    })
  }
  context[headersSchema] = compile({ schema: headersSchemaLowerCase, method, url, httpPart: 'headers' })
} else if (Object.hasOwn(schema, 'headers')) {
  FSTWRN001('headers', method, url)
}

export interface AddContentTypeParser<
  RawServer extends RawServerBase = RawServerDefault,
  RawRequest extends RawRequestDefaultExpression<RawServer> = RawRequestDefaultExpression<RawServer>,
  RouteGeneric extends RouteGenericInterface = RouteGenericInterface,
  SchemaCompiler extends FastifySchema = FastifySchema,
  TypeProvider extends FastifyTypeProvider = FastifyTypeProviderDefault
> {
  (
    contentType: string | string[] | RegExp,
    opts: {
      bodyLimit?: number;
    },
    parser: FastifyContentTypeParser<RawServer, RawRequest, RouteGeneric, SchemaCompiler, TypeProvider>
  ): void;
  (contentType: string | string[] | RegExp, parser: FastifyContentTypeParser<RawServer, RawRequest, RouteGeneric, SchemaCompiler, TypeProvider>): void;
  <parseAs extends string | Buffer>(
    contentType: string | string[] | RegExp,
    opts: {
      parseAs: parseAs extends Buffer ? 'buffer' : 'string';
      bodyLimit?: number;
    },
    parser: FastifyBodyParser<parseAs, RawServer, RawRequest, RouteGeneric, SchemaCompiler, TypeProvider>
  ): void;
}
